def most_frequent(lst: list[int]) -> int:
    if not lst:
        raise ValueError("List must not be empty")
    counts = {}
    for x in lst:
        counts[x] = counts.get(x, 0) + 1
    max_count = max(counts.values())
    candidates = [k for k, v in counts.items() if v == max_count]
    return min(candidates)
